item.description:
使用@ControllerAdvice 和 @ExceptionHandler 处理异常 这种方式比较通用，也能对异常统一处理
/** * */ @ControllerAdvice(assignableTypes = {ExceptionController.class}) @ResponseBody public class GlobalExceptionHandler { ErrorResponse illegalArgumentResponse = new ErrorResponse(new IllegalArgumentException(&#34;参数错误!&#34;)); ErrorResponse resourseNotFoundResponse = new ErrorResponse(new ResourceNotFoundException(&#34;Sorry, the resourse not found!&#34;)); @ExceptionHandler(value = Exception.class)// 拦截所有异常, 这里只是为了演示，一般情况下一个方法特定处理一种异常  public ResponseEntity&lt;ErrorResponse&gt; exceptionHandler(Exception e) { if (e instanceof IllegalArgumentException) { return ResponseEntity.status(400).body(illegalArgumentResponse); } else if (e instanceof ResourceNotFoundException) { return ResponseEntity.status(404).body(resourseNotFoundResponse); } return null; } } ResponseStatusException MyResourceNotFoundException.java
@ResponseStatus(code = HttpStatus.NOT_FOUND) public class MyResourceNotFoundException extends RuntimeException { public MyResourceNotFoundException(){ } public MyResourceNotFoundException(String message){ super(message); } } Controller.
